#!/usr/bin/env python3
"""Find exact Pi0 expert module names for LoRA."""
import os
import torch
os.environ['HF_HUB_OFFLINE'] = '1'

from lerobot.policies.pi0 import PI0Policy

policy = PI0Policy.from_pretrained('lerobot/pi0_base')

print("=== Expert modules ===")
try:
    expert = policy.model.paligemma_with_expert.expert
    print(f"Expert type: {type(expert).__name__}")
    for name, module in expert.named_modules():
        print(f"  expert.{name}: {type(module).__name__}")
except Exception as e:
    print(f"Error accessing expert: {e}")

print("\n=== All modules with 'expert' in name ===")
for name, module in policy.named_modules():
    if 'expert' in name.lower():
        print(f"  {name}: {type(module).__name__}")

print("\n=== paligemma_with_expert children ===")
for name, child in policy.model.paligemma_with_expert.named_children():
    print(f"  {name}: {type(child).__name__}")
    for name2, child2 in child.named_children():
        print(f"    {name2}: {type(child2).__name__}")

print("\n=== Linear layers in expert (if exists) ===")
for name, module in policy.model.named_modules():
    if isinstance(module, torch.nn.Linear) and 'expert' in name.lower():
        print(f"  {name}: {module.in_features} -> {module.out_features}")

print("\n=== All top-level model children ===")
for name, child in policy.model.named_children():
    print(f"  {name}: {type(child).__name__}")

print("\n=== policy.model.paligemma_with_expert type ===")
pwe = policy.model.paligemma_with_expert
print(f"Type: {type(pwe).__name__}")
print(f"Children: {[n for n, _ in pwe.named_children()]}")

# Check if there's a separate action expert
print("\n=== Checking for action_expert ===")
for name, module in policy.model.named_modules():
    if 'action' in name.lower() and isinstance(module, torch.nn.Linear):
        print(f"  {name}: {module.in_features} -> {module.out_features}")

print("\n=== First 20 Linear layers in policy.model ===")
count = 0
for name, module in policy.model.named_modules():
    if isinstance(module, torch.nn.Linear) and count < 20:
        print(f"  {name}: {module.in_features} -> {module.out_features}")
        count += 1

print("\n=== Last 20 Linear layers in policy.model ===")
all_linear = [(name, module) for name, module in policy.model.named_modules() if isinstance(module, torch.nn.Linear)]
for name, module in all_linear[-20:]:
    print(f"  {name}: {module.in_features} -> {module.out_features}")

print(f"\nTotal linear layers: {len(all_linear)}")
